/**
 * Login Page
 * Integrated with AuthContext and auth.api for backend connection
 * 
 * Features:
 * - Email/password login
 * - Remember me checkbox
 * - Error handling
 * - Loading states
 * - Redirect on success
 * - Links to forgot password and register
 */

import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { useAuth } from '@/contexts/AuthContext';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from '@/components/ui/form';
import { Checkbox } from '@/components/ui/checkbox';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { Loader, AlertCircle, Eye, EyeOff } from 'lucide-react';

// Validation schema
const loginSchema = z.object({
  email: z.string().email('Invalid email address'),
  password: z.string().min(6, 'Password must be at least 6 characters'),
  rememberMe: z.boolean().default(false),
});

type LoginFormData = z.infer<typeof loginSchema>;

interface LocationState {
  from?: { pathname: string };
}

export const LoginPage: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const { login, isLoading, error: authError, clearError } = useAuth();

  const [showPassword, setShowPassword] = useState(false);
  const [apiError, setApiError] = useState<string | null>(null);

  // Get the page user was trying to access
  const from = (location.state as LocationState)?.from?.pathname || '/dashboard';

  const form = useForm<LoginFormData>({
    resolver: zodResolver(loginSchema),
    defaultValues: {
      email: '',
      password: '',
      rememberMe: false,
    },
  });

  // Clear errors when user starts typing
  useEffect(() => {
    if (authError) {
      clearError();
    }
  }, [form.watch('email'), form.watch('password')]);

  const onSubmit = async (data: LoginFormData) => {
    setApiError(null);
    
    try {
      await login(data.email, data.password);
      
      // Redirect to the page they were trying to access or dashboard
      navigate(from, { replace: true });
    } catch (error: any) {
      const errorMessage = error?.response?.data?.error?.message || 
                          error?.message || 
                          'Login failed. Please try again.';
      setApiError(errorMessage);
    }
  };

  const currentError = apiError || authError;

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-slate-50 to-slate-100 px-4">
      <div className="w-full max-w-md">
        {/* Header */}
        <div className="text-center mb-8">
          <h1 className="text-3xl font-bold text-slate-900">MaxHub ERP</h1>
          <p className="text-slate-600 mt-2">Enterprise Resource Planning System</p>
        </div>

        {/* Card */}
        <div className="bg-white rounded-lg shadow-lg p-8">
          {/* Title */}
          <h2 className="text-xl font-semibold text-slate-900 mb-6">Sign In</h2>

          {/* Error Alert */}
          {currentError && (
            <Alert variant="destructive" className="mb-6">
              <AlertCircle className="h-4 w-4" />
              <AlertDescription>{currentError}</AlertDescription>
            </Alert>
          )}

          {/* Redirect Notification */}
          {from !== '/dashboard' && (
            <Alert className="mb-6 bg-blue-50 border-blue-200">
              <AlertDescription className="text-blue-800">
                You'll be redirected to {from} after login
              </AlertDescription>
            </Alert>
          )}

          {/* Form */}
          <Form {...form}>
            <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-5">
              {/* Email Field */}
              <FormField
                control={form.control}
                name="email"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Email Address</FormLabel>
                    <FormControl>
                      <Input
                        type="email"
                        placeholder="your@email.com"
                        disabled={isLoading}
                        {...field}
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              {/* Password Field */}
              <FormField
                control={form.control}
                name="password"
                render={({ field }) => (
                  <FormItem>
                    <div className="flex items-center justify-between">
                      <FormLabel>Password</FormLabel>
                      <a
                        href="/auth/forgot-password"
                        className="text-xs text-blue-600 hover:text-blue-700"
                      >
                        Forgot?
                      </a>
                    </div>
                    <FormControl>
                      <div className="relative">
                        <Input
                          type={showPassword ? 'text' : 'password'}
                          placeholder="••••••••"
                          disabled={isLoading}
                          {...field}
                        />
                        <button
                          type="button"
                          onClick={() => setShowPassword(!showPassword)}
                          disabled={isLoading}
                          className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600 disabled:opacity-50"
                        >
                          {showPassword ? (
                            <EyeOff className="h-4 w-4" />
                          ) : (
                            <Eye className="h-4 w-4" />
                          )}
                        </button>
                      </div>
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              {/* Remember Me Checkbox */}
              <FormField
                control={form.control}
                name="rememberMe"
                render={({ field }) => (
                  <FormItem>
                    <div className="flex items-center space-x-2">
                      <Checkbox
                        id="rememberMe"
                        checked={field.value}
                        onCheckedChange={field.onChange}
                        disabled={isLoading}
                      />
                      <label
                        htmlFor="rememberMe"
                        className="text-sm text-slate-600 cursor-pointer hover:text-slate-900"
                      >
                        Remember me for 30 days
                      </label>
                    </div>
                  </FormItem>
                )}
              />

              {/* Submit Button */}
              <Button
                type="submit"
                disabled={isLoading}
                className="w-full h-10 font-medium"
              >
                {isLoading ? (
                  <>
                    <Loader className="mr-2 h-4 w-4 animate-spin" />
                    Signing in...
                  </>
                ) : (
                  'Sign In'
                )}
              </Button>
            </form>
          </Form>

          {/* Divider */}
          <div className="my-6 relative">
            <div className="absolute inset-0 flex items-center">
              <div className="w-full border-t border-slate-200" />
            </div>
            <div className="relative flex justify-center text-sm">
              <span className="px-2 bg-white text-slate-500">Or</span>
            </div>
          </div>

          {/* Footer Links */}
          <div className="text-center space-y-3">
            <p className="text-sm text-slate-600">
              Don't have an account?{' '}
              <a
                href="/auth/register"
                className="text-blue-600 font-medium hover:text-blue-700"
              >
                Sign up
              </a>
            </p>

            <div className="flex items-center justify-center space-x-4 text-xs">
              <a
                href="/auth/forgot-password"
                className="text-slate-600 hover:text-slate-900"
              >
                Forgot Password
              </a>
              <span className="text-slate-300">•</span>
              <a
                href="/"
                className="text-slate-600 hover:text-slate-900"
              >
                Back to Home
              </a>
            </div>
          </div>
        </div>

        {/* Demo Credentials */}
        <div className="mt-6 bg-slate-900 text-slate-100 rounded-lg p-4 text-sm">
          <p className="font-semibold mb-2">🧪 Demo Credentials:</p>
          <p>Email: <span className="font-mono bg-slate-800 px-2 py-1 rounded">demo@example.com</span></p>
          <p>Password: <span className="font-mono bg-slate-800 px-2 py-1 rounded">DemoPass@123</span></p>
        </div>
      </div>
    </div>
  );
};

export default LoginPage;
